const fs = require('fs')
const path = require('path')
const { FRAMEWORK_CONVENTIONS } = require('../constants')

/**
 * 通过框架约定快速检测项目类型
 * 对于有 configCheck 的框架（如 SvelteKit），会读取配置文件判断实际模式
 */
function detectFramework(projectRoot) {
  const pkgPath = path.join(projectRoot, 'package.json')
  if (!fs.existsSync(pkgPath)) {
    return { name: null, impliedType: null, note: null }
  }

  const pkg = JSON.parse(fs.readFileSync(pkgPath, 'utf-8'))
  const allDeps = {
    ...pkg.dependencies,
    ...pkg.devDependencies,
  }

  for (const convention of FRAMEWORK_CONVENTIONS) {
    const { detect } = convention
    if (detect.dependency && allDeps[detect.dependency]) {
      // 检查是否需要读取配置文件进一步判断
      if (convention.configCheck) {
        const actualMode = checkConfigForSpaMode(projectRoot, convention.configCheck)
        if (actualMode === 'spa') {
          return {
            name: convention.name,
            impliedType: 'spa',
            note: convention.configCheck.spaNote,
          }
        }
      }

      return {
        name: convention.name,
        impliedType: convention.impliedType,
        note: convention.note,
      }
    }
  }

  return { name: null, impliedType: null, note: null }
}

/**
 * 读取配置文件，检查是否配置为 SPA 模式
 * 先去除注释行，避免注释中的内容被误匹配
 */
function checkConfigForSpaMode(projectRoot, configCheck) {
  const { configFiles, spaPatterns } = configCheck

  for (const configFile of configFiles) {
    const configPath = path.join(projectRoot, configFile)
    if (!fs.existsSync(configPath)) continue

    try {
      const rawContent = fs.readFileSync(configPath, 'utf-8')
      // 去除单行注释（// ...）和多行注释（/* ... */），避免注释中的内容被误匹配
      const content = rawContent
        .replace(/\/\/.*$/gm, '')
        .replace(/\/\*[\s\S]*?\*\//g, '')

      for (const pattern of spaPatterns) {
        if (pattern.test(content)) {
          return 'spa'
        }
      }
    } catch (e) {
      // 读取失败，跳过
    }
  }

  return 'default'
}

module.exports = { detectFramework }
